import React, { useEffect, useState, useCallback, useMemo } from 'react';
import api from '../api/axiosConfig';
import { useTheme } from '../context/ThemeContext';
import ReactMarkdown from 'react-markdown';
import {
  Trash2,
  Download,
  Archive,
  Calendar,
  ShieldCheck,
  Eye,
  X,
  BarChart3,
  AlignLeft
} from 'lucide-react';
import toast from 'react-hot-toast';

const VaultPage = () => {
  const { isDark } = useTheme();
  const [history, setHistory] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedItem, setSelectedItem] = useState(null);

  /* ─── Memoized Fetch ─── */
  const fetchHistory = useCallback(async () => {
    try {
      const res = await api.get('/portfolio/history');
      const data = res.data?.data || res.data || [];
      setHistory(Array.isArray(data) ? data.filter(item => item && item.id) : []);
    } catch {
      toast.error('VAULT_SYNC_ERROR: UNABLE_TO_REACH_DATA_NODE');
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchHistory();
  }, [fetchHistory]);

  /* ─── Optimized Actions ─── */
  const handleDelete = async (id) => {
    if (!window.confirm('CRITICAL: Purge this node from memory?')) return;
    try {
      await api.delete(`/portfolio/${id}`);
      setHistory(prev => prev.filter(item => item.id !== id));
      toast.success('NODE_PURGED');
    } catch {
      toast.error('WIPE_FAILURE');
    }
  };

  const handleDownload = useCallback(async (item) => {
    try {
      const res = await api.post('/portfolio/export', item, { responseType: 'blob' });
      const url = URL.createObjectURL(new Blob([res.data], { type: 'application/pdf' }));
      const a = document.createElement('a');
      a.href = url;
      a.download = `FINIFY_STRATEGY_${item.id}.pdf`;
      a.click();
      URL.revokeObjectURL(url);
    } catch {
      toast.error('EXPORT_ERROR');
    }
  }, []);

  /* ─── Scroll Management ─── */
  useEffect(() => {
    const originalStyle = window.getComputedStyle(document.body).overflow;
    if (selectedItem) document.body.style.overflow = 'hidden';
    return () => (document.body.style.overflow = originalStyle);
  }, [selectedItem]);

  /* ─── Memoized Component Renderers ─── */
  const emptyView = useMemo(() => (
    <div style={emptyState}>AWAITING_DATA_INITIALIZATION...</div>
  ), []);

  if (loading) return <div style={centerStyle}>SYNCHRONIZING_CORE_VAULT...</div>;

  return (
    <div className="reveal-node" style={containerStyle}>
      <header style={headerRow}>
        <h2 style={headerStyle}>
          <Archive size={40} color="var(--accent-primary)" /> STRATEGY_VAULT
        </h2>
        <div style={vaultBadge}>
          <BarChart3 size={20} /> {history.length} NODES_ACTIVE
        </div>
      </header>

      <div style={listStyle}>
        {history.length === 0 ? emptyView : history.map(item => (
          <article key={item.id} className="vault-card" style={cardStyle}>
            <div style={cardMeta}>
              <div style={metaGroup}>
                <span style={metaText}><Calendar size={18} /> {new Date(item.created_at).toLocaleDateString()}</span>
                <span style={riskTag}><ShieldCheck size={18} /> RISK_LEVEL: {item.risk_score ?? '--'}</span>
              </div>

              <div style={cardActions}>
                <button style={iconBtn} onClick={() => setSelectedItem(item)}><Eye size={32} /></button>
                <button style={iconBtn} onClick={() => handleDownload(item)}><Download size={32} /></button>
                <button style={deleteBtn} onClick={() => handleDelete(item.id)}><Trash2 size={32} /></button>
              </div>
            </div>

            <h4 style={titleStyle}>{item.goal || 'ANONYMOUS_STRATEGY'}</h4>
            <p style={labelSmall}><AlignLeft size={16} /> EXECUTIVE_SUMMARY</p>
            <div className="markdown-vault">
              <ReactMarkdown>{item.summary || '_No summary data available._'}</ReactMarkdown>
            </div>
          </article>
        ))}
      </div>

      {/* ── Modal Section ── */}
      {selectedItem && (
        <div style={modalOverlay(isDark)} onClick={() => setSelectedItem(null)}>
          <div style={modalContent(isDark)} onClick={e => e.stopPropagation()}>
            <div style={modalHeader(isDark)}>
              <span style={modalId}>NODE_DATA // SYNC_ID_{selectedItem.id}</span>
              <button style={closeBtn} onClick={() => setSelectedItem(null)}><X size={40} /></button>
            </div>
            <div style={modalBody}>
              <h3 style={modalTitle}>{selectedItem.goal}</h3>
              <p style={modalLabel}><AlignLeft size={20} /> AGENTIC_RATIONALE</p>
              <div className="markdown-vault modal-md">
                <ReactMarkdown>{selectedItem.rationale || '_Detail data corrupted or missing._'}</ReactMarkdown>
              </div>
            </div>
          </div>
        </div>
      )}

      <style>{`
        .markdown-vault p { color: var(--text-primary); font-size: 1.25rem; line-height: 1.8; margin-bottom: 1.5rem; }
        .markdown-vault h1, .markdown-vault h2 { color: var(--accent-primary); font-size: 1.5rem; margin-top: 2rem; font-weight: 900; }
        .modal-md p { color: var(--text-primary); font-size: 1.35rem; }
        .vault-card { transition: transform 0.3s cubic-bezier(0.2, 0, 0, 1), border-color 0.3s; }
        .vault-card:hover { border-color: var(--accent-primary) !important; transform: translateY(-10px); box-shadow: 0 30px 60px var(--shadow-color); }
        .reveal-node { animation: fadeIn 0.5s ease-out forwards; }
        @keyframes fadeIn { from { opacity: 0; transform: translateY(30px); } to { opacity: 1; transform: translateY(0); } }
      `}</style>
    </div>
  );
};

/* ────────────────────────────── Optimized Style Kit ────────────────────────────── */

const containerStyle = { padding: '5rem 2.5rem', maxWidth: '1450px', margin: '0 auto' };
